module RefModule (
    input clk,
    input clear,
    input [3:0] d,
    output [3:0] q);reg [3:0] q_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (clear)
        q_reg <= 4'b0;
    else
        q_reg <= d;
end

assign q = q_reg;

endmodule
